#!/usr/bin/env bash
set -euo pipefail

if [ ! -f "package.json" ] || [ ! -d "src/app" ]; then
  echo "ERRO: rode este script dentro da pasta cejas-sistema-gestao-vercel."
  exit 1
fi

mkdir -p 'src/app/(system)/orcamentos'

python3 - <<'PYCODE'
from pathlib import Path

page = '"use client";\n\nimport { useMemo, useState } from "react";\n\ntype CustomerType = "associado" | "nao_associado";\ntype DayType = "dias_uteis" | "sabado" | "dom_fer";\n\ntype CatalogItem = {\n  id: string;\n  name: string;\n  category: string;\n  details: string;\n  value: number;\n  priceRule: "tabela_real" | "fixo";\n};\n\ntype QuoteLine = {\n  id: string;\n  itemName: string;\n  room: string;\n  quantity: number;\n  details: string;\n  unitValue: number;\n};\n\nconst emptyCatalogForm: Omit<CatalogItem, "id"> = {\n  name: "",\n  category: "",\n  details: "",\n  value: 0,\n  priceRule: "fixo"\n};\n\nconst money = new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" });\n\nfunction formatCurrency(value: number) {\n  return money.format(Number.isFinite(value) ? value : 0);\n}\n\nfunction formatDateBR(value: string) {\n  if (!value) return "";\n  const [year, month, day] = value.split("-");\n  return `${day}/${month}/${year}`;\n}\n\nfunction formatTime(value: string) {\n  return value ? value.replace(":", "H") : "--:--";\n}\n\nexport default function OrcamentosPage() {\n  const [issuer, setIssuer] = useState("EDUARDO");\n  const [company, setCompany] = useState("");\n  const [eventName, setEventName] = useState("");\n  const [notes, setNotes] = useState("");\n  const [date, setDate] = useState("");\n  const [startTime, setStartTime] = useState("");\n  const [endTime, setEndTime] = useState("");\n  const [customerType, setCustomerType] = useState<CustomerType>("nao_associado");\n  const [dayType, setDayType] = useState<DayType>("dias_uteis");\n  const [selectedCatalogId, setSelectedCatalogId] = useState("");\n  const [items, setItems] = useState<QuoteLine[]>([]);\n  const [catalog, setCatalog] = useState<CatalogItem[]>([]);\n  const [isCatalogOpen, setIsCatalogOpen] = useState(false);\n  const [editingId, setEditingId] = useState<string | null>(null);\n  const [catalogForm, setCatalogForm] = useState(emptyCatalogForm);\n\n  const total = useMemo(\n    () => items.reduce((sum, item) => sum + Number(item.quantity || 0) * Number(item.unitValue || 0), 0),\n    [items]\n  );\n\n  const periodTitle = date\n    ? `${formatDateBR(date)} - ${formatTime(startTime)} AS ${formatTime(endTime)}`\n    : "DATA NÃO INFORMADA";\n\n  function addCatalogItemToQuote(item: CatalogItem) {\n    setItems((current) => [\n      ...current,\n      {\n        id: `line-${Date.now()}`,\n        itemName: item.category || item.name,\n        room: item.name,\n        quantity: 1,\n        details: item.details || item.name,\n        unitValue: Number(item.value || 0)\n      }\n    ]);\n  }\n\n  function addSelectedItem() {\n    const selected = catalog.find((item) => item.id === selectedCatalogId);\n    if (!selected) return;\n    addCatalogItemToQuote(selected);\n    setSelectedCatalogId("");\n  }\n\n  function addCustomItem() {\n    setItems((current) => [\n      ...current,\n      {\n        id: `custom-${Date.now()}`,\n        itemName: "",\n        room: "",\n        quantity: 1,\n        details: "",\n        unitValue: 0\n      }\n    ]);\n  }\n\n  function updateQuoteLine(id: string, key: keyof QuoteLine, value: string | number) {\n    setItems((current) => current.map((item) => (item.id === id ? { ...item, [key]: value } : item)));\n  }\n\n  function saveCatalogItem() {\n    const normalized: CatalogItem = {\n      id: editingId || `catalog-${Date.now()}`,\n      name: catalogForm.name.trim(),\n      category: catalogForm.category.trim(),\n      details: catalogForm.details.trim(),\n      value: Number(catalogForm.value || 0),\n      priceRule: catalogForm.priceRule\n    };\n\n    if (!normalized.name) return;\n\n    setCatalog((current) => {\n      if (editingId) return current.map((item) => (item.id === editingId ? normalized : item));\n      return [...current, normalized];\n    });\n    setEditingId(null);\n    setCatalogForm(emptyCatalogForm);\n  }\n\n  function editCatalogItem(item: CatalogItem) {\n    setEditingId(item.id);\n    setCatalogForm({\n      name: item.name,\n      category: item.category,\n      details: item.details,\n      value: item.value,\n      priceRule: item.priceRule\n    });\n  }\n\n  async function saveBudget() {\n    const payload = {\n      title: company ? `Orçamento - ${company}` : "Orçamento sem solicitante",\n      company,\n      eventName,\n      issuer,\n      customerType,\n      dayType,\n      notes,\n      date,\n      startTime,\n      endTime,\n      total,\n      status: "rascunho",\n      items: items.map((item) => ({\n        id: item.id,\n        rubric: item.itemName || "Orçamento",\n        description: item.room || item.itemName || "Item sem nome",\n        quantity: Number(item.quantity || 0),\n        unitValue: Number(item.unitValue || 0),\n        details: item.details || ""\n      }))\n    };\n\n    const response = await fetch("/api/orcamentos", {\n      method: "POST",\n      headers: { "Content-Type": "application/json" },\n      body: JSON.stringify(payload)\n    });\n\n    if (!response.ok) {\n      alert("Não foi possível salvar o orçamento. Confira as variáveis do Supabase e tente novamente.");\n      return;\n    }\n\n    alert("Orçamento enviado para o servidor.");\n  }\n\n  return (\n    <main className="orc-v2026-page">\n      <header className="orc-v2026-topbar">\n        <h1>🏢 CEJAS - Orçamentos v.2026</h1>\n        <div className="orc-v2026-actions">\n          <button type="button" className="orc-v2026-pill orc-v2026-pill-blue">Conectado 000:00</button>\n          <button type="button" className="orc-v2026-pill orc-v2026-pill-dark">Voltar ao Painel</button>\n          <button type="button" className="orc-v2026-pill orc-v2026-pill-dark" onClick={() => setIsCatalogOpen(true)}>⚙ Cadastro de Itens</button>\n          <button type="button" className="orc-v2026-pill orc-v2026-pill-print" onClick={() => window.print()}>🖨 Imprimir / PDF A4</button>\n          <button type="button" className="orc-v2026-pill orc-v2026-pill-save" onClick={saveBudget}>Salvar PDF no Servidor</button>\n        </div>\n      </header>\n\n      <div className="orc-v2026-workspace">\n        <section className="orc-v2026-form-card" aria-label="Formulário do orçamento">\n          <div className="orc-v2026-section">\n            <h2>👤 EMISSOR COMERCIAL</h2>\n            <label>\n              <span>Elaborado por</span>\n              <input value={issuer} onChange={(event) => setIssuer(event.target.value.toUpperCase())} />\n            </label>\n          </div>\n\n          <div className="orc-v2026-section">\n            <h2>💼 REGRAS DE PREÇO</h2>\n            <div className="orc-v2026-segment orc-v2026-segment-two">\n              <button type="button" className={customerType === "associado" ? "active" : ""} onClick={() => setCustomerType("associado")}>ASSOCIADO</button>\n              <button type="button" className={customerType === "nao_associado" ? "active" : ""} onClick={() => setCustomerType("nao_associado")}>NÃO ASSOCIADO</button>\n            </div>\n            <div className="orc-v2026-segment">\n              <button type="button" className={dayType === "dias_uteis" ? "active" : ""} onClick={() => setDayType("dias_uteis")}>DIAS ÚTEIS</button>\n              <button type="button" className={dayType === "sabado" ? "active" : ""} onClick={() => setDayType("sabado")}>SÁBADO</button>\n              <button type="button" className={dayType === "dom_fer" ? "active" : ""} onClick={() => setDayType("dom_fer")}>DOM/FER</button>\n            </div>\n\n            <label>\n              <span>Empresa Solicitante</span>\n              <input value={company} onChange={(event) => setCompany(event.target.value)} placeholder="Empresa Solicitante" />\n            </label>\n            <label>\n              <span>Nome do Evento</span>\n              <input value={eventName} onChange={(event) => setEventName(event.target.value)} placeholder="Nome do Evento" />\n            </label>\n          </div>\n\n          <div className="orc-v2026-section">\n            <h2>📄 INFOS ADICIONAIS</h2>\n            <label>\n              <textarea value={notes} onChange={(event) => setNotes(event.target.value)} placeholder="Ex: Montagem especial, observações do cliente..." />\n            </label>\n          </div>\n\n          <div className="orc-v2026-section orc-v2026-schedule-section">\n            <div className="orc-v2026-section-head">\n              <h2>📅 CRONOGRAMA</h2>\n              <button type="button" className="orc-v2026-small-dark">+ Novo Dia</button>\n            </div>\n\n            <div className="orc-v2026-schedule-card">\n              <div className="orc-v2026-time-row">\n                <input type="date" value={date} onChange={(event) => setDate(event.target.value)} />\n                <input type="time" value={startTime} onChange={(event) => setStartTime(event.target.value)} />\n                <input type="time" value={endTime} onChange={(event) => setEndTime(event.target.value)} />\n                <button type="button" className="orc-v2026-remove-date" onClick={() => { setDate(""); setStartTime(""); setEndTime(""); }}>×</button>\n              </div>\n\n              <select value={selectedCatalogId} onChange={(event) => setSelectedCatalogId(event.target.value)}>\n                <option value="">+ ADICIONAR ITEM DA TABELA...</option>\n                {catalog.length === 0 ? <option disabled>Nenhum item cadastrado</option> : null}\n                {catalog.map((item) => <option key={item.id} value={item.id}>{item.name} — {formatCurrency(item.value)}</option>)}\n              </select>\n\n              <button type="button" className="orc-v2026-add-selected" onClick={addSelectedItem}>✅ ADICIONAR ITEM SELECIONADO AO ORÇAMENTO</button>\n              <button type="button" className="orc-v2026-outline-action" onClick={addCustomItem}>⌁ + ITEM PERSONALIZADO / CORINGA</button>\n              <button type="button" className="orc-v2026-outline-action" onClick={() => setIsCatalogOpen(true)}>⊙ CADASTRAR / EDITAR ITENS DO SISTEMA</button>\n            </div>\n          </div>\n\n          {items.length > 0 ? (\n            <div className="orc-v2026-lines-editor">\n              <h3>Itens adicionados ao orçamento</h3>\n              {items.map((item) => (\n                <div className="orc-v2026-line-editor" key={item.id}>\n                  <input value={item.itemName} onChange={(event) => updateQuoteLine(item.id, "itemName", event.target.value)} placeholder="Item / Sala" />\n                  <input type="number" min="0" value={item.quantity} onChange={(event) => updateQuoteLine(item.id, "quantity", Number(event.target.value))} placeholder="Qtd." />\n                  <input value={item.details} onChange={(event) => updateQuoteLine(item.id, "details", event.target.value)} placeholder="Detalhes / Recursos" />\n                  <input type="number" min="0" value={item.unitValue} onChange={(event) => updateQuoteLine(item.id, "unitValue", Number(event.target.value))} placeholder="Valor" />\n                  <button type="button" onClick={() => setItems((current) => current.filter((line) => line.id !== item.id))}>Excluir</button>\n                </div>\n              ))}\n            </div>\n          ) : null}\n        </section>\n\n        <section className="orc-v2026-paper-wrap" aria-label="Prévia A4 do orçamento">\n          <article className="orc-v2026-paper">\n            <header className="orc-v2026-paper-header">\n              <div className="orc-v2026-paper-logo">CEJAS</div>\n              <div className="orc-v2026-company-block">\n                <strong>DOCUMENTO AUXILIAR DE VENDA - ORÇAMENTO</strong>\n                <span>De: Centro Empresarial de Jaraguá do Sul - CEJAS</span>\n                <span>CNPJ: 83.784.124/0001-32 - IE: Isenta</span>\n                <span>Rua Octaviano Lombardi, 100. Czerniewicz | CEP 89255-055</span>\n                <span>Jaraguá do Sul - SC</span>\n                <span>(47) 3275-7000 – Fax (47) 3275-7001</span>\n              </div>\n            </header>\n\n            <div className="orc-v2026-paper-meta">\n              <span><b>Data:</b> {date ? formatDateBR(date) : "__/__/____"}</span>\n              <span><b>Elaborado por:</b> {issuer || "__________"}</span>\n            </div>\n\n            <div className="orc-v2026-paper-title">O R Ç A M E N T O&nbsp;&nbsp; L O C A Ç Ã O&nbsp;&nbsp; D E&nbsp;&nbsp; S A L A S&nbsp;&nbsp; E&nbsp;&nbsp; E Q U I P A M E N T O S</div>\n\n            <div className="orc-v2026-client-box">\n              <div><b>Solicitante:</b> <span>{company || "________________________"}</span></div>\n              <div><b>Evento:</b> <span>{eventName || "________________________"}</span></div>\n            </div>\n\n            <h3 className="orc-v2026-period-title">▌ {periodTitle}</h3>\n\n            <table className="orc-v2026-paper-table">\n              <thead>\n                <tr>\n                  <th>Nº</th>\n                  <th>Item / Sala</th>\n                  <th>Qtd.</th>\n                  <th>Detalhes / Recursos</th>\n                  <th>Valor unitário</th>\n                  <th>Valor final</th>\n                </tr>\n              </thead>\n              <tbody>\n                {items.length === 0 ? (\n                  <tr>\n                    <td colSpan={6} className="orc-v2026-empty-row">Nenhum item adicionado.</td>\n                  </tr>\n                ) : items.map((item, index) => (\n                  <tr key={item.id}>\n                    <td>{String(index + 1).padStart(2, "0")}</td>\n                    <td><b>{(item.itemName || item.room || "ITEM SEM NOME").toUpperCase()}</b></td>\n                    <td>{item.quantity || 0}</td>\n                    <td>{item.details}</td>\n                    <td>{formatCurrency(item.unitValue)}</td>\n                    <td><b>{formatCurrency(Number(item.quantity || 0) * Number(item.unitValue || 0))}</b></td>\n                  </tr>\n                ))}\n                <tr>\n                  <td colSpan={5} className="orc-v2026-subtotal-label">SUBTOTAL DO PERÍODO:</td>\n                  <td><b>{formatCurrency(total)}</b></td>\n                </tr>\n              </tbody>\n            </table>\n\n            <div className="orc-v2026-total-row">\n              <span>TOTAL GERAL:</span>\n              <strong>{formatCurrency(total)}</strong>\n            </div>\n\n            <section className="orc-v2026-conditions">\n              <h4>OBSERVAÇÕES E CONDIÇÕES</h4>\n              <p>• Orçamento válido por <b>72 horas</b>. A pré-reserva garante o espaço por este período; após o prazo, o evento é considerado cancelado.</p>\n              <p><b>ATENÇÃO: O HORÁRIO LIMITE PARA FECHAMENTO TOTAL DO PRÉDIO É IMPRETERIVELMENTE ÀS 22:00H.</b></p>\n              <p><b>FORMAS DE PAGAMENTO:</b></p>\n              <p>- Transferência/Depósito: Sicredi Norte (Ag 2602, c/c 04247-2, titular: CEJAS).</p>\n              <p>- Boleto Bancário via Sicredi Norte.</p>\n              <p>- PIX CNPJ: 83.784.124/0001-32</p>\n            </section>\n\n            <footer className="orc-v2026-paper-footer">\n              <p>Permanecemos à disposição.</p>\n              <p>Atenciosamente,</p>\n              <p><b>{issuer || "CEJAS"}</b></p>\n              <span>SISTEMA COMERCIAL CEJAS V2026</span>\n            </footer>\n          </article>\n        </section>\n      </div>\n\n      {isCatalogOpen ? (\n        <div className="orc-v2026-modal-backdrop" role="dialog" aria-modal="true">\n          <div className="orc-v2026-modal">\n            <header className="orc-v2026-modal-header">\n              <div>\n                <h2>Cadastro de Itens do Orçamento</h2>\n                <p>Cadastre, edite e exclua itens da tabela.</p>\n              </div>\n              <button type="button" onClick={() => setIsCatalogOpen(false)}>Fechar</button>\n            </header>\n\n            <div className="orc-v2026-modal-body">\n              <aside className="orc-v2026-catalog-form">\n                <h3>{editingId ? "Editar item" : "Cadastrar novo item"}</h3>\n                <label><span>Nome</span><input value={catalogForm.name} onChange={(event) => setCatalogForm((current) => ({ ...current, name: event.target.value }))} placeholder="Ex: Diurno - Sala Básica" /></label>\n                <label><span>Categoria</span><input value={catalogForm.category} onChange={(event) => setCatalogForm((current) => ({ ...current, category: event.target.value }))} placeholder="Ex: Auditório / Sala / Equipamentos" /></label>\n                <label><span>Detalhes</span><textarea value={catalogForm.details} onChange={(event) => setCatalogForm((current) => ({ ...current, details: event.target.value }))} placeholder="Detalhes do item" /></label>\n                <label><span>Valor</span><input type="number" min="0" value={catalogForm.value} onChange={(event) => setCatalogForm((current) => ({ ...current, value: Number(event.target.value) }))} /></label>\n                <label><span>Aplica regra de preço?</span><select value={catalogForm.priceRule} onChange={(event) => setCatalogForm((current) => ({ ...current, priceRule: event.target.value as CatalogItem["priceRule"] }))}><option value="fixo">Não - valor fixo</option><option value="tabela_real">Tabela real</option></select></label>\n                <div className="orc-v2026-catalog-actions">\n                  <button type="button" className="primary" onClick={saveCatalogItem}>Salvar item</button>\n                  <button type="button" onClick={() => { setEditingId(null); setCatalogForm(emptyCatalogForm); }}>Limpar</button>\n                </div>\n              </aside>\n\n              <section className="orc-v2026-catalog-table-card">\n                <h3>Itens cadastrados</h3>\n                <table className="orc-v2026-catalog-table">\n                  <thead>\n                    <tr><th>Item</th><th>Categoria</th><th>Valor</th><th>Regra</th><th>Ações</th></tr>\n                  </thead>\n                  <tbody>\n                    {catalog.length === 0 ? (\n                      <tr><td colSpan={5} className="orc-v2026-empty-catalog">Nenhum item cadastrado ainda.</td></tr>\n                    ) : catalog.map((item) => (\n                      <tr key={item.id}>\n                        <td><b>{item.name}</b><span>{item.details}</span></td>\n                        <td>{item.category || "-"}</td>\n                        <td>{formatCurrency(item.value)}</td>\n                        <td>{item.priceRule === "tabela_real" ? "Tabela real" : "Fixo"}</td>\n                        <td className="orc-v2026-catalog-buttons">\n                          <button type="button" className="use" onClick={() => addCatalogItemToQuote(item)}>Usar</button>\n                          <button type="button" className="edit" onClick={() => editCatalogItem(item)}>Editar</button>\n                          <button type="button" className="delete" onClick={() => setCatalog((current) => current.filter((row) => row.id !== item.id))}>Excluir</button>\n                        </td>\n                      </tr>\n                    ))}\n                  </tbody>\n                </table>\n              </section>\n            </div>\n          </div>\n        </div>\n      ) : null}\n    </main>\n  );\n}\n'
css_block = '/* CEJAS Orçamentos v.2026 - layout fiel ao sistema antigo */\n.orc-v2026-page{margin:-38px -32px -70px;background:#e5e7eb;color:#172033;min-height:100vh;padding:28px 30px 90px;font-family:Arial,Helvetica,sans-serif}.orc-v2026-topbar{height:86px;background:#0b1322;color:#fff;display:flex;align-items:center;justify-content:space-between;padding:0 34px;box-shadow:0 12px 28px rgba(15,23,42,.28);margin-bottom:44px}.orc-v2026-topbar h1{font-size:32px;line-height:1;margin:0;font-weight:900;letter-spacing:-.6px}.orc-v2026-actions{display:flex;gap:12px;align-items:center;flex-wrap:wrap}.orc-v2026-pill{border:0;border-radius:14px;min-height:45px;padding:0 18px;color:#fff;font-weight:900;box-shadow:0 10px 22px rgba(15,23,42,.12)}.orc-v2026-pill-blue{background:#213d78}.orc-v2026-pill-dark{background:#222a38}.orc-v2026-pill-print{background:#2f64e9}.orc-v2026-pill-save{background:linear-gradient(90deg,#8b46f6,#f046b2)}.orc-v2026-workspace{display:grid;grid-template-columns:minmax(470px,620px) minmax(760px,1fr);gap:72px;align-items:start;max-width:1780px;margin:0 auto}.orc-v2026-form-card{background:#fff;border-radius:20px;box-shadow:0 18px 45px rgba(15,23,42,.12);padding:28px 28px 34px;max-height:calc(100vh - 165px);overflow:auto}.orc-v2026-section{border-bottom:1px solid #e5e7eb;padding-bottom:22px;margin-bottom:22px}.orc-v2026-section:last-child{border-bottom:0;margin-bottom:0}.orc-v2026-section h2,.orc-v2026-section-head h2{margin:0 0 17px;color:#202a3d;font-size:18px;letter-spacing:.32em;font-weight:950}.orc-v2026-section label,.orc-v2026-catalog-form label{display:grid;gap:7px;margin-bottom:15px;color:#202a3d;font-weight:900}.orc-v2026-section label span,.orc-v2026-catalog-form label span{font-size:14px;letter-spacing:0;text-transform:none;color:#2f3a4d}.orc-v2026-section input,.orc-v2026-section select,.orc-v2026-section textarea,.orc-v2026-line-editor input,.orc-v2026-catalog-form input,.orc-v2026-catalog-form select,.orc-v2026-catalog-form textarea{width:100%;min-height:42px;border:1px solid #cfd5df;background:#f8fafc;color:#172033;border-radius:11px;padding:0 13px;outline:0}.orc-v2026-section textarea,.orc-v2026-catalog-form textarea{min-height:102px;padding-top:13px;resize:vertical}.orc-v2026-segment{height:47px;display:grid;grid-template-columns:repeat(3,1fr);border:1px solid #d7dde6;border-radius:12px;overflow:hidden;margin-bottom:14px;background:#fff}.orc-v2026-segment-two{grid-template-columns:1fr 1fr}.orc-v2026-segment button{border:0;background:#fff;color:#969fac;font-weight:950;letter-spacing:.03em}.orc-v2026-segment button.active{background:#10192a;color:#fff}.orc-v2026-section-head{display:flex;align-items:center;justify-content:space-between;margin-bottom:17px}.orc-v2026-section-head h2{margin:0}.orc-v2026-small-dark{border:0;background:#10192a;color:#fff;border-radius:12px;font-weight:950;min-height:42px;padding:0 18px}.orc-v2026-schedule-section{border-bottom:0;margin-bottom:0;padding-bottom:0}.orc-v2026-schedule-card{border:1px solid #e4e9f1;border-radius:20px;background:#fbfcff;padding:18px;box-shadow:0 10px 24px rgba(47,100,233,.06)}.orc-v2026-time-row{display:grid;grid-template-columns:1fr 1fr 1fr 24px;gap:11px;align-items:center;margin-bottom:15px}.orc-v2026-remove-date{border:0;background:transparent;color:#ff4054;font-weight:950;font-size:18px}.orc-v2026-add-selected{width:100%;min-height:44px;border:0;border-radius:10px;background:#edf5ff;color:#0754dc;font-weight:950;margin-top:12px}.orc-v2026-outline-action{width:100%;min-height:43px;border:1px dashed #d8e0ec;border-radius:10px;background:#fff;color:#53627a;font-weight:950;margin-top:10px}.orc-v2026-lines-editor{margin-top:22px;border:1px solid #e3e9f1;border-radius:16px;padding:16px;background:#fbfcff}.orc-v2026-lines-editor h3{margin:0 0 12px;color:#172033}.orc-v2026-line-editor{display:grid;grid-template-columns:1.2fr .45fr 1.25fr .65fr auto;gap:9px;margin-bottom:9px}.orc-v2026-line-editor button{border:0;border-radius:10px;background:#ef2f3d;color:#fff;font-weight:950;padding:0 12px}.orc-v2026-paper-wrap{display:flex;justify-content:center}.orc-v2026-paper{width:794px;min-height:1123px;background:#fff;box-shadow:0 24px 60px rgba(15,23,42,.18);padding:42px 38px 36px;color:#172033;position:relative}.orc-v2026-paper-header{display:flex;justify-content:space-between;gap:26px;border-bottom:2px solid #1d2634;padding-bottom:24px}.orc-v2026-paper-logo{width:74px;height:74px;background:#777;display:grid;place-items:center;color:#fff;font-weight:950;font-size:25px}.orc-v2026-company-block{text-align:right;font-size:12px;line-height:1.32}.orc-v2026-company-block strong{font-size:12px}.orc-v2026-company-block span{display:block}.orc-v2026-paper-meta{display:flex;justify-content:space-between;margin:22px 0 14px;font-size:12px}.orc-v2026-paper-title{background:#f0f2f5;border:1px solid #d9dee7;text-align:center;font-size:11px;font-weight:950;letter-spacing:.32em;padding:12px 8px;margin-bottom:17px}.orc-v2026-client-box{border:1px solid #d9dee7;min-height:72px;padding:18px 20px;font-size:12px;display:grid;gap:8px}.orc-v2026-client-box span{display:inline-block;border-bottom:1px solid #1d2634;min-width:180px;margin-left:35px}.orc-v2026-period-title{font-size:15px;margin:22px 0 8px;color:#172033}.orc-v2026-paper-table{width:100%;border-collapse:collapse;font-size:11px}.orc-v2026-paper-table th,.orc-v2026-paper-table td{border:1px solid #dce1e9;padding:8px 9px;vertical-align:top}.orc-v2026-paper-table th{background:#f0f2f5;text-align:left;font-weight:950}.orc-v2026-paper-table th:nth-child(1),.orc-v2026-paper-table td:nth-child(1),.orc-v2026-paper-table th:nth-child(3),.orc-v2026-paper-table td:nth-child(3){text-align:center;width:50px}.orc-v2026-paper-table th:nth-child(5),.orc-v2026-paper-table td:nth-child(5),.orc-v2026-paper-table th:nth-child(6),.orc-v2026-paper-table td:nth-child(6){text-align:right;width:112px}.orc-v2026-empty-row{text-align:center!important;color:#7b8494;height:45px}.orc-v2026-subtotal-label{text-align:right!important;font-weight:950}.orc-v2026-total-row{display:flex;align-items:center;justify-content:flex-end;gap:22px;margin:16px 0 0 auto;font-size:16px;font-weight:950}.orc-v2026-total-row strong{font-size:20px}.orc-v2026-conditions{margin-top:260px;background:#f5f6f8;border-top:27px solid #dfe3e9;padding:13px 15px 16px;font-size:11px;line-height:1.35}.orc-v2026-conditions h4{margin:0 0 12px;font-size:11px;letter-spacing:.28em}.orc-v2026-conditions p{margin:7px 0}.orc-v2026-paper-footer{font-size:11px;margin-top:24px;position:relative}.orc-v2026-paper-footer p{margin:8px 0}.orc-v2026-paper-footer span{position:absolute;right:0;bottom:0;color:#93a0b5;font-size:10px}.orc-v2026-modal-backdrop{position:fixed;inset:0;background:rgba(0,0,0,.73);backdrop-filter:blur(6px);z-index:1000;display:grid;place-items:start center;padding:44px 24px;overflow:auto}.orc-v2026-modal{width:min(1380px,92vw);background:#fff;color:#172033;border-radius:18px;overflow:hidden;box-shadow:0 30px 90px rgba(0,0,0,.55)}.orc-v2026-modal-header{height:112px;background:#0b1322;color:#fff;display:flex;align-items:center;justify-content:space-between;padding:0 34px}.orc-v2026-modal-header h2{margin:0 0 8px;font-size:32px}.orc-v2026-modal-header p{margin:0;color:#cbd5e1;font-size:17px}.orc-v2026-modal-header button{border:0;border-radius:12px;background:#273244;color:#fff;font-weight:950;min-height:42px;padding:0 18px}.orc-v2026-modal-body{display:grid;grid-template-columns:430px 1fr;gap:24px;padding:28px}.orc-v2026-catalog-form,.orc-v2026-catalog-table-card{border:1px solid #dce2eb;border-radius:16px;background:#f9fafc;padding:22px}.orc-v2026-catalog-form h3,.orc-v2026-catalog-table-card h3{margin:0 0 18px;font-size:18px}.orc-v2026-catalog-actions{display:flex;gap:8px}.orc-v2026-catalog-actions button{border:0;border-radius:10px;background:#10192a;color:#fff;font-weight:950;min-height:39px;padding:0 14px}.orc-v2026-catalog-actions .primary{background:#2f64e9}.orc-v2026-catalog-table{width:100%;border-collapse:collapse;background:#fff}.orc-v2026-catalog-table th,.orc-v2026-catalog-table td{border:1px solid #dce2eb;padding:13px;text-align:left;vertical-align:middle}.orc-v2026-catalog-table th{background:#f0f2f5;font-size:12px;font-weight:950}.orc-v2026-catalog-table td span{display:block;color:#5d687a;font-size:12px;margin-top:4px}.orc-v2026-empty-catalog{text-align:center!important;color:#7b8494;height:120px}.orc-v2026-catalog-buttons{display:grid;gap:6px;width:82px}.orc-v2026-catalog-buttons button{border:0;border-radius:10px;color:#fff;font-weight:950;min-height:35px}.orc-v2026-catalog-buttons .use{background:#2f64e9}.orc-v2026-catalog-buttons .edit{background:#111827}.orc-v2026-catalog-buttons .delete{background:#ef2f3d}@media(max-width:1500px){.orc-v2026-workspace{grid-template-columns:520px minmax(760px,1fr);gap:42px}.orc-v2026-topbar{height:auto;min-height:86px;align-items:flex-start;flex-direction:column;gap:14px;padding:20px 26px}}@media(max-width:1180px){.orc-v2026-workspace{grid-template-columns:1fr}.orc-v2026-form-card{max-height:none}.orc-v2026-paper-wrap{justify-content:flex-start;overflow:auto}.orc-v2026-modal-body{grid-template-columns:1fr}}@media(max-width:760px){.orc-v2026-page{margin:-24px -16px -60px;padding:16px}.orc-v2026-topbar h1{font-size:24px}.orc-v2026-line-editor,.orc-v2026-time-row{grid-template-columns:1fr}.orc-v2026-paper{transform-origin:top left;min-width:794px}.orc-v2026-modal-header{height:auto;min-height:100px;padding:22px;align-items:flex-start;gap:16px}.orc-v2026-modal-header h2{font-size:24px}.orc-v2026-modal-body{padding:16px}.orc-v2026-catalog-buttons{width:auto}}@media print{.sidebar,.orc-v2026-topbar,.orc-v2026-form-card,.orc-v2026-modal-backdrop{display:none!important}.app-main,.orc-v2026-page{margin:0!important;padding:0!important;background:#fff!important}.orc-v2026-workspace{display:block!important}.orc-v2026-paper-wrap{display:block!important}.orc-v2026-paper{box-shadow:none!important;width:100%!important;m